VALUES
  ('fire-eq-tech-moex-02520', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「建築技術規則」之規定，有關防火區劃之敘述何者錯誤？', '["防火區劃之牆壁，應突出建築物外牆面五十公分以上", "防火區劃之牆壁與其交接處之外牆面長度有一百公分以上，且該外牆構造具有與防火區劃之牆壁同等 以上防火時效者，得免突出", "貫穿防火區劃牆壁或樓地板之風管，應在貫穿部位任一側之風管內裝設防火閘門或閘板，其與貫穿部 位合成之構造，並應具有一小時以上之防火時效", "管道間之維修門並應具有一小時以上防火時效及遮煙性能"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02521', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '某一建築物地上層有30層，建築高度為100公尺，依照「建築技術規則」之規定，設置防災中心，試問 下列何者錯誤？', '["防災中心設於避難層的直下層", "防災中心樓地板面積為45平方公尺", "防災中心設置具備防災、警報、通報、滅火、消防及其他必要之監控系統", "防災中心以1小時以上防火時效之牆壁、防火門窗等防火設備及該層防火構造之樓板予以區劃分隔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02522', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依照「各類場所消防安全設備設置標準」之規定，下列何者錯誤？', '["總樓地板面積1,000平方公尺以上之地下建築物，應設置連結送水管", "有效採光面積未達該居室樓地板面積百分之二者，應設置緊急照明設備", "地下層供甲類場所使用，樓地板面積合計1,000平方公尺以上者，應設置瓦斯漏氣火警自動警報設備", "樓地板面積在100平方公尺以上之居室，其天花板下方80公分範圍內之有效通風面積未達該居室樓地 板面積百分之二者，應設置排煙設備"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02523', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依照「各類場所消防安全設備檢修及申報作業基準」之規定，各類場所的消防安全設備，每次檢修時間 之間隔，甲類場所不得少於X個月，甲類以外之場所不得少於Y個月，請問前述X，Y為何？', '["X=4，Y=9", "X=5，Y=10", "X=5，Y=11", "X=6，Y=12"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02524', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依照「各類場所消防安全設備設置標準」，一般建築物的消防安全設備之緊急電源供電容量規定，下列 何者錯誤？', '["自動撒水設備為30分鐘以上", "二氧化碳滅火設備為60分鐘以上", "火警自動警報設備為10分鐘以上", "緊急照明燈設備為20分鐘以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02525', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依照「公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法」之規定，六類物品之製造場所，其外 牆設施外側，與廠區外鄰近的博物館之安全距離至少為X公尺；如與廠區外鄰近的收容人數在300人以 上之車站，其安全距離至少為Y公尺，請問前述X，Y為何？', '["30，20", "20，20", "40，30", "50，30"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02526', 'fire-eq-tech', 'fire-eq-tech-moex-100-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '下列有關建築物火災「閃燃」（flash over）現象之敘述，何者有誤？', '["「閃燃」（flash over）現象通常發生在建築物火災的成長期", "一旦發生「閃燃」（flash over）現象，該居室中的人即無法生存", "就「閃燃時間」（F.O.T）而言，同種類等面積之裝潢材料中，影響最大部位為壁面", "在避難對策上，延遲建築物火災到達「閃燃」階段，至為重要"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "807f4e747202", "answer_pdf_sha1": "6a97d4653b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "火災學概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02527', 'fire-eq-tech', 'fire-eq-tech-moex-100-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '下列有關可燃物之敘述，何者有誤？', '["氣體、液體、固體三者中，以氣體熱傳導度最小", "分子之每莫耳燃燒熱在100 kcal以上之氣體或液體均屬可燃性", "物質雖可與氧化合，若不能產生發熱反應者，仍非可燃物", "可燃物熱傳導度需在0.01 kcal/cm‧sec°C以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "807f4e747202", "answer_pdf_sha1": "6a97d4653b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "火災學概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02528', 'fire-eq-tech', 'fire-eq-tech-moex-100-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '火災成長常數K=600 sec/MW1/2時，是屬於下列何者？', '["極快速成長", "快速成長", "中速成長", "慢速成長"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "807f4e747202", "answer_pdf_sha1": "6a97d4653b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "火災學概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02529', 'fire-eq-tech', 'fire-eq-tech-moex-100-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '瓦斯火災通常被歸類為何種火災？', '["A類火災", "B類火災", "C類火災", "D類火災"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "807f4e747202", "answer_pdf_sha1": "6a97d4653b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "火災學概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
